@app.before_request
def load_session_data():
    session_id = session_interface.get_session_id()
    if session_id:
        session_data = session_interface.load_session(session_id)
        for key, value in session_data.items():
            session[key] = value


@app.after_request
def save_session_data(response):
    session_id = session_interface.get_session_id()
    if not session_id and session:
        session_id = session_interface.generate_sid()
        response.set_cookie('session_id', session_id, httponly=True)
    
    if session_id and session:
        session_data = dict(session)
        session_interface.save_session(session_id, session_data)
    
    return response


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    user_id = data.get('user_id', 1)
    
    session['username'] = username
    session['user_id'] = user_id
    session['logged_in'] = True
    
    return jsonify({
        'status': 'success',
        'message': 'Logged in successfully',
        'user': username
    })


@app.route('/logout', methods=['POST'])
def logout():
    session_id = session_interface.get_session_id()
    if session_id:
        session_interface.delete_session(session_id)
    
    session.clear()
    
    response = jsonify({
        'status': 'success',
        'message': 'Logged out successfully'
    })
    response.set_cookie('session_id', '', expires=0)
    return response


