@app.route('/cache/invalidate', methods=['POST'])
def invalidate_cache_endpoint():
    data = request.get_json() or {}
    pattern = data.get('pattern', 'cache:*')
    invalidate_cache(pattern)
    return jsonify({
        'status': 'success',
        'message': f'Cache invalidated for pattern: {pattern}'
    })


@app.route('/cache/set', methods=['POST'])
def set_cache():
    data = request.get_json()
    key = data.get('key')
    value = data.get('value')
    expiration = data.get('expiration', 300)
    
    redis_client_str.setex(f"custom:{key}", expiration, json.dumps(value))
    
    return jsonify({
        'status': 'success',
        'message': 'Cache set successfully',
        'key': key
    })


@app.route('/cache/get/<key>', methods=['GET'])
def get_cache(key):
    value = redis_client_str.get(f"custom:{key}")
    if value:
        return jsonify({
            'status': 'success',
            'key': key,
            'value': json.loads(value)
        })
    return jsonify({
        'status': 'not_found',
        'key': key,
        'value': None
    }), 404


